                        <button key={id} type="button"
                          onClick={() => setAssignees(prev =>
                            isSelected
                              ? prev.filter(a => a !== id)
                              : [...prev, id]
                          )}
                          className={`w-full flex items-center
                            gap-2 px-3 py-2 text-sm text-left
                            transition-colors
                            ${isDark
                              ? 'hover:bg-white/5 text-slate-300'
                              : 'hover:bg-slate-50 text-slate-700'
