                            font-bold flex items-center
                            justify-center shrink-0">
                            {name.charAt(0).toUpperCase()}
                          </div>
                          <span className="flex-1 truncate">
                            {name}
                          </span>
                          {isSelected && (
                            <span className="material-symbols-outlined
                              text-[14px] text-indigo-500">check</span>
                          )}
                        </button>
                      )
                    })}
                  </div>
                </div>
              )}
            </div>
          </div>

          <div className="pt-2 flex justify-end gap-3 mt-4">
            <button
              type="button"
              onClick={onClose}
              className={`px-4 py-2 rounded-xl text-sm
                font-semibold border transition-all
                ${isDark
                  ? 'border-[rgba(255,255,255,0.08)] text-slate-400 hover:bg-white/5'
                  : 'border-slate-200 text-slate-600 hover:bg-slate-50'
                }`}
            >
              Cancel
            </button>
            <button
              type="button"
              onClick={handleCreate}
              disabled={creating}
              className="px-6 py-2 rounded-xl text-sm
                         font-semibold bg-indigo-600
                         hover:bg-indigo-700 text-white
                         shadow-lg shadow-indigo-600/20
                         transition-all active:scale-95
                         disabled:opacity-50 flex items-center gap-2"
            >
              {creating && <div className="size-4 rounded-full border-2 border-white border-t-transparent animate-spin" />}
              {creating ? 'Creating...' : 'Create Task'}
            </button>
          </div>
        </div>
      </div>
    </div>
  )
}

function ProjectMembersPanel({
  isDark, projectId, orgId,
  projectMembers, orgMembers,
  onClose, onMembersUpdated,
  showConfirmInPanel
}) {
  const [adding, setAdding] = useState(null)
  const [removing, setRemoving] = useState(null)
  const [panelError, setPanelError] = useState(null)

  const projectMemberIds = projectMembers.map(
    m => m._id?.toString() || m?.toString()
  )

  const availableToAdd = orgMembers.filter(m => {
    const userId = (m.user?._id || m._id)?.toString()
    return !projectMemberIds.includes(userId)
  })

  const getMemberRole = (userId) => {
    const orgMember = orgMembers.find(m =>
      (m.user?._id || m._id)?.toString() ===
      userId?.toString()
    )
    return orgMember?.role || 'developer'
  }

  const handleAdd = async (email, userId) => {
    try {
      setAdding(userId)
      setPanelError(null)
      await api.post(
        `/organizations/${orgId}/projects/${projectId}/members`,
        { email }
      )
      onMembersUpdated()
    } catch (err) {
      setPanelError(err.response?.data?.message || 'Failed to add member')
    } finally {
      setAdding(null)
    }
  }

  const handleRemove = async (userId, name) => {
    showConfirmInPanel({
      title: 'Remove from Project',
      message: `Remove ${name} from this project? They won't be able to see this board.`,
      confirmText: 'Remove',
      onConfirm: async () => {
        try {
          setRemoving(userId)
          setPanelError(null)
          await api.delete(
            `/organizations/${orgId}/projects/${projectId}/members/${userId}`
          )
          onMembersUpdated()
        } catch (err) {
          setPanelError(err.response?.data?.message || 'Failed to remove member')
        } finally {
          setRemoving(null)
        }
      }
    })
  }

  return (
    <div className={`fixed right-0 top-0 h-full
      w-[340px] flex flex-col z-50
      shadow-[-8px_0_32px_rgba(0,0,0,0.2)]
      ${isDark
        ? 'bg-[#141414] border-l border-[rgba(255,255,255,0.07)]'
        : 'bg-white border-l border-slate-200'
      }`}>

      <div className={`h-12 flex items-center
        justify-between px-4 border-b shrink-0
        ${isDark
          ? 'border-[rgba(255,255,255,0.06)]'
          : 'border-slate-200'
        }`}>
        <h3 className={`text-sm font-semibold
          ${isDark ? 'text-white' : 'text-slate-900'}`}>
          Project Members
        </h3>
        <button onClick={onClose}
          className={`p-1.5 rounded-md transition-colors
            ${isDark
              ? 'text-slate-500 hover:text-slate-200 hover:bg-[rgba(255,255,255,0.06)]'
              : 'text-slate-400 hover:text-slate-700 hover:bg-slate-100'
            }`}>
          <span className="material-symbols-outlined
                           text-[18px]">close</span>
        </button>
      </div>

      <div className="flex-1 overflow-y-auto
                      custom-scrollbar p-4 space-y-6">

        {panelError && (
          <div className={`p-3 rounded-lg text-xs flex items-center gap-2
            ${isDark ? 'bg-red-500/10 text-red-400 border border-red-500/20'
                     : 'bg-red-50 text-red-600 border border-red-100'}`}>
            <span className="material-symbols-outlined text-[16px]">error</span>
            {panelError}
          </div>
        )}

        <div>
          <p className={`text-[10px] font-bold uppercase
            tracking-widest mb-3
            ${isDark ? 'text-slate-500' : 'text-slate-500'}`}>
            On this project ({projectMembers.length})
          </p>
          <div className="space-y-1">
            {projectMembers.map(m => (
              <div key={m._id}
                className={`flex items-center gap-3
                  px-3 py-2.5 rounded-xl group
                  ${isDark
                    ? 'bg-[rgba(255,255,255,0.03)]'
                    : 'bg-slate-50'
                  }`}>
                <div className="size-8 rounded-full
                  bg-indigo-500 text-white text-xs
                  font-bold flex items-center
                  justify-center overflow-hidden shrink-0">
                  {m.avatar
                    ? <img src={m.avatar}
                           className="w-full h-full
                                      object-cover" />
                    : m.name?.charAt(0)?.toUpperCase()
                  }
                </div>
                <div className="flex-1 min-w-0">
                  <p className={`text-sm font-medium truncate
                    ${isDark ? 'text-white' : 'text-slate-900'}`}>
                    {m.name}
                  </p>
                  <p className="text-xs text-slate-500 truncate">
                    {m.email}
                  </p>
                </div>
                {getMemberRole(m._id) !== 'owner' && (
                  <button
                    onClick={() => handleRemove(m._id, m.name)}
                    disabled={removing === m._id}
                    className="opacity-0 group-hover:opacity-100
                      p-1 rounded transition-all text-red-400
                      hover:bg-red-500/10 cursor-pointer">
                    <span className="material-symbols-outlined
                                     text-[16px]">
                      {removing === m._id
                        ? 'hourglass_empty' : 'person_remove'}
                    </span>
                  </button>
                )}
              </div>
            ))}
            {projectMembers.length === 0 && (
              <p className={`text-xs text-center py-4
                ${isDark ? 'text-slate-600' : 'text-slate-400'}`}>
                No members yet
              </p>
            )}
          </div>
        </div>

        {availableToAdd.length > 0 && (
          <div>
            <p className={`text-[10px] font-bold uppercase
              tracking-widest mb-3
              ${isDark ? 'text-slate-500' : 'text-slate-500'}`}>
              Add from organization
            </p>
            <div className="space-y-1">
              {availableToAdd.map(m => {
                const userId = m.user?._id || m._id
                const name = m.user?.name || m.name || '?'
                const email = m.user?.email || m.email || ''
                const avatar = m.user?.avatar || m.avatar

                return (
                  <div key={userId}
                    className={`flex items-center gap-3
                      px-3 py-2.5 rounded-xl
                      ${isDark
                        ? 'hover:bg-[rgba(255,255,255,0.04)]'
                        : 'hover:bg-slate-50'
                      }`}>
                    <div className="size-8 rounded-full
                      bg-slate-500 text-white text-xs
                      font-bold flex items-center
                      justify-center overflow-hidden shrink-0">
                      {avatar
                        ? <img src={avatar}
                               className="w-full h-full
                                          object-cover" />
                        : name.charAt(0).toUpperCase()
                      }
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className={`text-sm font-medium
                        truncate
                        ${isDark
                          ? 'text-slate-300'
                          : 'text-slate-700'
                        }`}>
                        {name}
                      </p>
                      <p className="text-xs text-slate-500
                                    truncate">
                        {email}
                      </p>
                    </div>
                    <button
                      onClick={() => handleAdd(email, userId)}
                      disabled={adding === userId}
                      className="flex items-center gap-1
                        px-2.5 py-1 rounded-lg text-xs
                        font-semibold bg-indigo-600
                        hover:bg-indigo-700 text-white
                        disabled:opacity-50 transition-colors
                        shrink-0">
                      {adding === userId
                        ? <div className="size-3 rounded-full
                            border-2 border-white
                            border-t-transparent animate-spin" />
                        : <span className="material-symbols-outlined
                                           text-[14px]">add</span>
                      }
                      Add
                    </button>
                  </div>
                )
              })}
            </div>
          </div>
        )}
      </div>

      <div className={`p-4 border-t text-xs
        ${isDark
          ? 'border-[rgba(255,255,255,0.06)] text-slate-600'
          : 'border-slate-100 text-slate-400'
        }`}>
        Project members appear in task assignee dropdowns.
      </div>
    </div>
  )
}

export default function BoardPage() {
  const { orgId, projectId } = useParams()
  const { isDark } = useTheme()
  const navigate = useNavigate()
  const [board, setBoard] = useState(null)
  const [columns, setColumns] = useState([])
  const [tasksByColumn, setTasksByColumn] = useState({})
  const [members, setMembers] = useState([])
  const [orgMembers, setOrgMembers] = useState([])
  const [loading, setLoading] = useState(true)
  const [activeTask, setActiveTask] = useState(null)
  const [selectedTask, setSelectedTask] = useState(null)
  const [showCreateModal, setShowCreateModal] = useState(false)
  const [showMembersPanel, setShowMembersPanel] = useState(false)
  const [targetColumnId, setTargetColumnId] = useState(null)
  const [searchQuery, setSearchQuery] = useState('')
  const [toast, setToast] = useState(null)

  const showToast = useCallback((message, type = 'error') => {
    setToast({ message, type })
  }, [])
  const socketRef = useRef()
  const deletingRef = useRef(new Set())

  const sensors = useSensors(
    useSensor(PointerSensor, {
      activationConstraint: {
        distance: 5,
      },
    }),
    useSensor(KeyboardSensor, {
      coordinateGetter: sortableKeyboardCoordinates,
    })
  )

  const [confirmModal, setConfirmModal] = useState(null)

  const showConfirm = useCallback(({
    title, message, confirmText,
    confirmColor, onConfirm
  }) => {
    setConfirmModal({
      title, message, confirmText,
      confirmColor, onConfirm
    })
  }, [])

  const colWidth = React.useMemo(() => {
    const count = columns.length
    if (count === 0) return '280px'
    const available = window.innerWidth - 240 - (count + 1) * 12 - 32
    const w = Math.floor(available / count)
    return `${Math.max(220, Math.min(w, 340))}px`
  }, [columns.length])

  const totalTasks = React.useMemo(() => {
    return Object.values(tasksByColumn).flat().length
  }, [tasksByColumn])

  const getFilteredTasks = useCallback((colId) => {
    const tasks = tasksByColumn[colId] || []
    if (!searchQuery) return tasks
    return tasks.filter(t => {
      const q = searchQuery.toLowerCase().trim()
      return t.title?.toLowerCase().includes(q) ||
             t.description?.toLowerCase().includes(q) ||
             t.labels?.some(l => l.toLowerCase().includes(q))
    })
  }, [tasksByColumn, searchQuery])

  const fetchBoard = useCallback(async () => {
    try {
      setLoading(true)
      setError(null)

      // CORRECT: /api/organizations/:orgId/projects/:id
      const projectRes = await api.get(
        `/organizations/${orgId}/projects/${projectId}`
      )

      const projectData =
        projectRes.data?.data?.project ||
        projectRes.data?.data ||
        projectRes.data

      const boardData = projectData?.board
      const cols = boardData?.columns || []

      setProject(projectData)
      setBoard(boardData)
      setColumns(cols)

      if (!boardData?._id) {
        setLoading(false)
        return
      }

      // CORRECT: /api/tasks?boardId=:boardId
      const tasksRes = await api.get(
        `/tasks?boardId=${boardData._id}`
      )
      const allTasks = tasksRes.data?.data?.tasks || []

      // Group by column
      const grouped = {}
      cols.forEach(col => { grouped[col._id] = [] })
      allTasks.forEach(task => {
        const colId = task.column?._id || task.column
        if (grouped[colId]) {
          grouped[colId].push(task)
        }
      })
      Object.keys(grouped).forEach(colId => {
        grouped[colId].sort((a, b) => a.order - b.order)
      })
      setTasksByColumn(grouped)

      // Fetch PROJECT members for task assignment
      // These are users added to this specific project
      const projMembersRes = await api.get(
        `/organizations/${orgId}/projects/${projectId}/members`
      ).catch(() => null)

      if (projMembersRes) {
        const projMembers =
          projMembersRes.data?.data?.members || []
        setMembers(projMembers)
      }

      // Fetch ALL org members for "Add to project" panel
      const orgMembersRes = await api.get(
        `/organizations/${orgId}/members`
      )
      setOrgMembers(orgMembersRes.data?.data?.members || [])

    } catch (err) {
      console.error('Board fetch error:', err)
      setError(
        err.response?.data?.message ||
        err.message ||
        'Failed to load board'
      )
    } finally {
      setLoading(false)
    }
  }, [orgId, projectId])

  useEffect(() => {
    setLoading(true)
    setColumns([])
    setTasksByColumn({})
    if (orgId && projectId) {
      fetchBoard()
    }
  }, [orgId, projectId, fetchBoard])

  // Socket.io integration
  useEffect(() => {
    if (!board?._id) return

    const socketUrl = import.meta.env.VITE_SOCKET_URL ||
                     'http://localhost:5000'
    const socket = io(socketUrl, { withCredentials: true })
    socketRef.current = socket

    socket.emit('join:board', { boardId: board._id })

    socket.on('task:moved', () => {
      fetchBoard()
    })

    socket.on('task:created', ({ task }) => {
      const colId = task.column?._id || task.column
      setTasksByColumn(prev => {
        const colTasks = prev[colId] || []
        if (colTasks.some(t => t._id === task._id)) return prev
        return {
          ...prev,
          [colId]: [...colTasks, task]
        }
      })
    })

    socket.on('task:updated', ({ task }) => {
      const colId = task.column?._id || task.column
      setTasksByColumn(prev => ({
        ...prev,
        [colId]: (prev[colId] || []).map(t => t._id === task._id ? task : t)
      }))
      if (selectedTask?._id === task._id) setSelectedTask(task)
    })

    socket.on('task:deleted', ({ taskId }) => {
      setTasksByColumn(prev => {
        const next = { ...prev }
        Object.keys(next).forEach(cid => {
          next[cid] = next[cid].filter(t => t._id !== taskId)
        })
        return next
      })
      if (selectedTask?._id === taskId) setSelectedTask(null)
    })

    return () => {
      socket.emit('leave:board', { boardId: board._id })
      socket.disconnect()
    }
  }, [board?._id, selectedTask?._id, fetchBoard])

  // DnD Handlers
  const handleDragStart = (event) => {
    const { active } = event
    const task = Object.values(tasksByColumn).flat().find(t => t._id === active.id)
    setActiveTask(task)
  }

  const handleDragOver = useCallback((event) => {
    const { active, over } = event
    if (!over || !active) return
    if (active.id === over.id) return

    const activeId = String(active.id)
    const overId = String(over.id)

    // Find source column of active task
    let sourceColId = null
    for (const [colId, tasks] of
         Object.entries(tasksByColumn)) {
      if (tasks.some(t => String(t._id) === activeId)) {
        sourceColId = colId
        break
      }
    }
    if (!sourceColId) return

    // Determine target column
    // over.id could be a column id or a task id
    let targetColId = null

    // Check if over is a column directly
    if (columns.some(c => String(c._id) === overId)) {
      targetColId = overId
    } else {
      // over is a task ΓÇö find its column
      for (const [colId, tasks] of
           Object.entries(tasksByColumn)) {
        if (tasks.some(t => String(t._id) === overId)) {
          targetColId = colId
          break
        }
      }
    }

    if (!targetColId || sourceColId === targetColId) return

    setTasksByColumn(prev => {
      const next = { ...prev }
      const sourceTask = next[sourceColId]
        ?.find(t => String(t._id) === activeId)
      if (!sourceTask) return prev

      next[sourceColId] = next[sourceColId]
        .filter(t => String(t._id) !== activeId)
      next[targetColId] = [
        ...(next[targetColId] || []),
        { ...sourceTask, column: targetColId }
      ]
      return next
    })
  }, [tasksByColumn, columns])

  const handleAddColumn = async () => {
    const newColumnName = window.prompt('Enter column name:')
    if (!newColumnName) return
    try {
      // CORRECT: POST /api/boards/:boardId/columns
      const res = await api.post(
        `/boards/${board._id}/columns`,
        { name: newColumnName.trim() }
      )
      const newCol = res.data?.data?.column
      if (newCol) {
        setColumns(prev => [...prev, newCol])
        setTasksByColumn(prev => ({
          ...prev,
          [newCol._id]: []
        }))
      }
    } catch (err) {
      console.error('Column create error:', err)
    }
  }

  const handleDeleteColumn = async (columnId) => {
    showConfirm({
      title: 'Delete Column',
      message: 'Delete this column and all its tasks? Cannot be undone.',
      confirmText: 'Delete Column',
      confirmColor: 'bg-red-600 hover:bg-red-700',
      onConfirm: async () => {
        setConfirmModal(null)
        try {
          await api.delete(`/columns/${columnId}`)
          setColumns(prev => prev.filter(c => c._id !== columnId))
          setTasksByColumn(prev => {
            const next = { ...prev }
            delete next[columnId]
            return next
          })
        } catch (err) {
          console.error('Col delete error:', err)
        }
      }
    })
  }

  const handleDragEnd = useCallback(async (event) => {
    const { active, over } = event
    setActiveTask(null)

    if (!over || !active) return

    const activeId = String(active.id)
    const overId = String(over.id)

    // Find current column and index
    let currentColId = null
    let currentIdx = 0

    for (const [colId, tasks] of
         Object.entries(tasksByColumn)) {
      const idx = tasks.findIndex(
        t => String(t._id) === activeId
      )
      if (idx !== -1) {
        currentColId = colId
        currentIdx = idx
        break
      }
    }

    if (!currentColId) return

    const colTasks = tasksByColumn[currentColId] || []

    // Reorder within same column if over is a task
    const isOverTask = colTasks.some(
      t => String(t._id) === overId
    )

    if (isOverTask && activeId !== overId) {
      const oldIdx = colTasks.findIndex(
        t => String(t._id) === activeId
      )
      const newIdx = colTasks.findIndex(
        t => String(t._id) === overId
      )
      if (oldIdx !== -1 && newIdx !== -1 &&
          oldIdx !== newIdx) {
        const reordered = arrayMove(
          colTasks, oldIdx, newIdx
        )
        setTasksByColumn(prev => ({
          ...prev,
          [currentColId]: reordered
        }))
        currentIdx = newIdx
      }
    }

    try {
      await api.patch(`/tasks/${activeId}/move`, {
        newColumnId: currentColId,
        newOrder: currentIdx,
      })
    } catch (err) {
      console.error('Move task error:', err)
      fetchBoard()
    }
  }, [tasksByColumn, fetchBoard])

  const handleTaskCreated = useCallback((newTask, columnId) => {
    if (!newTask) return
    setTasksByColumn(prev => {
      const colTasks = prev[columnId] || []
      if (colTasks.some(t => t._id === newTask._id)) return prev
      return {
        ...prev,
        [columnId]: [...colTasks, newTask]
      }
    })
  }, [])

  const handleUpdateTask = (updatedTask) => {
    const colId = updatedTask.column?._id || updatedTask.column
    setTasksByColumn(prev => ({
      ...prev,
      [colId]: (prev[colId] || []).map(t => t._id === updatedTask._id ? updatedTask : t)
    }))
    setSelectedTask(updatedTask)
  }

  const handleDeleteTask = useCallback(async (taskId) => {
    if (deletingRef.current.has(taskId)) return
    deletingRef.current.add(taskId)

    // Close modal immediately before API call
    setConfirmModal(null)

    try {
      await api.delete(`/tasks/${taskId}`)

      // Update state after successful delete
      setTasksByColumn(prev => {
        const next = { ...prev }
        Object.keys(next).forEach(colId => {
          next[colId] = next[colId].filter(
            t => t._id !== taskId
          )
        })
        return next
      })
      setSelectedTask(prev =>
        prev?._id === taskId ? null : prev
      )
      showToast('Task deleted.', 'success')
    } catch (err) {
      console.error('Delete task error:', err)
      showToast(
        err.response?.data?.message ||
        'Failed to delete task',
        'error'
      )
      // Refetch to restore correct state
      fetchBoard()
    } finally {
      deletingRef.current.delete(taskId)
    }
  }, [showToast, fetchBoard])

  if (loading) return (
    <div className="flex-1 flex items-center justify-center">
      <div className="size-8 border-2 border-indigo-500
                      border-t-transparent rounded-full animate-spin" />
    </div>
  )

  return (
    <div
      className={`flex flex-col overflow-hidden
        ${isDark ? 'bg-[#0a0a0a]' : 'bg-[#f4f5f7]'}`}
      style={{ height: 'calc(100vh - 64px)' }}
    >

      {showMembersPanel && (
        <>
          <div
            className="fixed inset-0 bg-black/20 z-40"
            onClick={() => setShowMembersPanel(false)}
          />
          <ProjectMembersPanel
            isDark={isDark}
            projectId={projectId}
            orgId={orgId}
            projectMembers={members}
            orgMembers={orgMembers}
            onClose={() => setShowMembersPanel(false)}
            onMembersUpdated={() => {
              fetchBoard()
              setShowMembersPanel(false)
            }}
            showConfirmInPanel={showConfirm}
            showToastInPanel={showToast}
          />
        </>
      )}

      {/* Board Header */}
      <div className={`px-6 py-4 flex flex-wrap items-center
        justify-between gap-4 border-b shrink-0
        ${isDark
          ? 'bg-[#0f0f0f] border-[rgba(255,255,255,0.06)]'
          : 'bg-white border-slate-200'
        }`}>
        <div className="flex items-center gap-4">
          <button
            onClick={() => navigate('/projects')}
            className={`p-1.5 rounded-lg transition-colors
              ${isDark
                ? 'text-slate-500 hover:text-slate-200 hover:bg-white/5'
                : 'text-slate-400 hover:text-slate-700 hover:bg-slate-100'
              }`}
          >
            <span className="material-symbols-outlined
                             text-[20px]">
              arrow_back
            </span>
          </button>
          <div>
            <h1 className={`text-lg font-bold
              ${isDark ? 'text-white' : 'text-slate-900'}`}>
              {board?.name || 'Project Board'}
            </h1>
            <p className="text-xs text-slate-500 font-medium">
              {members.length} members ΓÇó {totalTasks} tasks
            </p>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <button
            onClick={() => setShowMembersPanel(p => !p)}
            className={`flex items-center gap-1.5 px-3
              py-1.5 rounded-lg text-xs font-medium
              transition-colors
              ${isDark
                ? 'border border-[rgba(255,255,255,0.08)] text-slate-400 hover:bg-[rgba(255,255,255,0.06)]'
                : 'border border-slate-200 text-slate-600 hover:bg-slate-50'
              }`}
          >
            <span className="material-symbols-outlined text-[16px]">
              group
            </span>
            Members
          </button>
          <div className="relative">
            <span className="material-symbols-outlined
                             absolute left-3 top-1/2 -translate-y-1/2
                             text-[16px] text-slate-500">
              search
            </span>
            <input
              type="text"
              placeholder="Search tasks..."
              value={searchQuery}
              onChange={e => setSearchQuery(e.target.value)}
              className={`pl-9 pr-4 py-1.5 rounded-lg border-none
                text-sm w-48 transition-all focus:w-64
                ${isDark
                  ? 'bg-[rgba(255,255,255,0.05)] text-white focus:bg-[rgba(255,255,255,0.08)]'
                  : 'bg-slate-100 text-slate-900 focus:bg-slate-200/50'
                }`}
            />
          </div>
          <button
            onClick={() => {
              setTargetColumnId(columns[0]?._id)
              setShowCreateModal(true)
            }}
            className="flex items-center gap-1.5 px-4 py-1.5
                       bg-indigo-600 hover:bg-indigo-700
                       text-white text-sm font-semibold
                       rounded-lg shadow-lg shadow-indigo-600/20
                       transition-all active:scale-95"
          >
            <span className="material-symbols-outlined
                             text-[18px]">
              add
            </span>
            New Task
          </button>
        </div>
      </div>

      {/* Board Layout */}
      <DndContext
        sensors={sensors}
        collisionDetection={pointerWithin}
        onDragStart={handleDragStart}
        onDragOver={handleDragOver}
        onDragEnd={handleDragEnd}
      >
        <div className={`flex-1 overflow-x-auto overflow-y-hidden
          ${isDark ? 'bg-[#0a0a0a]' : 'bg-[#f4f5f7]'}`}
          style={{ height: 'calc(100vh - 64px - 64px - 60px)' }}>
          <div className="flex gap-3 h-full px-4 py-3"
               style={{ minWidth: 'max-content', alignItems: 'stretch' }}>
            {columns.map(column => (
              <BoardColumn
                key={column._id}
                column={column}
                tasks={getFilteredTasks(column._id)}
                isDark={isDark}
                width={colWidth}
                onTaskClick={setSelectedTask}
                onAddTask={(cid) => {
                  setTargetColumnId(cid)
                  setShowCreateModal(true)
                }}
                onDeleteColumn={handleDeleteColumn}
                onDeleteTask={handleDeleteTask}
                showConfirm={showConfirm}
                setConfirmModal={setConfirmModal}
              />
            ))}

            {/* Add Column Button */}
            <div className="shrink-0" style={{ width: '280px' }}>
              <button
                onClick={handleAddColumn}
                className={`w-full h-12 rounded-xl border border-dashed
                  flex items-center justify-center gap-2 transition-all
                  ${isDark
                    ? 'border-[rgba(255,255,255,0.08)] text-slate-500 hover:bg-white/5 hover:border-slate-700'
                    : 'border-slate-200 text-slate-400 hover:bg-slate-50 hover:border-slate-300'
                  }`}
              >
                <span className="material-symbols-outlined text-[20px]">add</span>
                <span className="text-sm font-semibold">Add Column</span>
              </button>
            </div>
          </div>
        </div>

        <DragOverlay>
          {activeTask ? (
            <div className="w-[280px] rotate-3 cursor-grabbing">
              <TaskCard
                task={activeTask}
                isDark={isDark}
                onClick={() => {}}
                isDragging
              />
            </div>
          ) : null}
        </DragOverlay>
      </DndContext>

      {/* Modals & Panels */}
      {selectedTask && (
        <>
          <div
            className="fixed inset-0 bg-black/40 backdrop-blur-sm z-40"
            onClick={() => setSelectedTask(null)}
          />
          <TaskDetailPanel
            task={selectedTask}
            columns={columns}
            members={members}
            isDark={isDark}
            onClose={() => setSelectedTask(null)}
            onUpdate={handleUpdateTask}
            onDelete={handleDeleteTask}
            showConfirm={showConfirm}
          />
        </>
      )}

      {showCreateModal && board && (
        <CreateTaskModal
          isDark={isDark}
          defaultColumnId={targetColumnId || columns[0]?._id}
          columns={columns}
          members={members}
          boardId={board._id}
          projectId={projectId}
          orgId={orgId}
          onClose={() => {
            setShowCreateModal(false)
            setTargetColumnId(null)
          }}
          onCreated={handleTaskCreated}
        />
      )}

      {confirmModal && (
        <ConfirmModal
          isDark={isDark}
          title={confirmModal.title}
          message={confirmModal.message}
          confirmText={confirmModal.confirmText}
          confirmColor={confirmModal.confirmColor}
          onConfirm={confirmModal.onConfirm}
          onCancel={() => setConfirmModal(null)}
        />
      )}

      {toast && (
        <Toast
          message={toast.message}
          type={toast.type}
          onClose={() => setToast(null)}
        />
      )}
    </div>
  )
}

import { useState, useEffect, useRef, useCallback } from 'react'
import { useSelector, useDispatch } from 'react-redux'
import { useNavigate } from 'react-router-dom'
import { setCredentials } from '../store/slices/authSlice'
import api from '../services/axios'
import { useTheme } from '../context/ThemeContext'
import Toast from '../components/Toast'
import ConfirmModal from '../components/ConfirmModal'

const formatAction = (action, metadata = {}, isDark = false) => {
  if (!action) return null
  let parts = [action]

  // Bold task title
  if (metadata.taskTitle) {
    const title = metadata.taskTitle
    parts = parts.flatMap(part => {
      if (typeof part !== 'string') return [part]
      const segments = part.split(title)
      return segments.reduce((acc, segment, i) => {
        if (i === segments.length - 1) return [...acc, segment]
        return [...acc, segment, <strong key={`task-${i}`} className={isDark ? 'text-slate-100' : 'text-slate-900'}>{title}</strong>]
      }, [])
    })
  }

  // Bold column names (from/to)
  if (metadata.from) {
    const from = metadata.from
    parts = parts.flatMap(part => {
      if (typeof part !== 'string') return [part]
      const segments = part.split(from)
      return segments.reduce((acc, segment, i) => {
        if (i === segments.length - 1) return [...acc, segment]
        return [...acc, segment, <strong key={`from-${i}`} className={isDark ? 'text-slate-100' : 'text-slate-900'}>{from}</strong>]
      }, [])
    })
  }
  if (metadata.to) {
    const to = metadata.to
    parts = parts.flatMap(part => {
      if (typeof part !== 'string') return [part]
      const segments = part.split(to)
      return segments.reduce((acc, segment, i) => {
        if (i === segments.length - 1) return [...acc, segment]
        return [...acc, segment, <strong key={`to-${i}`} className={isDark ? 'text-slate-100' : 'text-slate-900'}>{to}</strong>]
      }, [])
    })
  }

  return parts
}

const DashboardPage = () => {
  const dispatch = useDispatch()
  const navigate = useNavigate()
  const { user, token, activeOrgId } = useSelector(s => s.auth)
  const { isDark } = useTheme()
  const firstName = user?.name?.split(' ')[0] || 'there'

  // orgId from Redux activeOrgId or user organization
  const orgId = activeOrgId
             || user?.organization?._id
             || (typeof user?.organization === 'string'
                 ? user.organization : null)

  const [hasOrg, setHasOrg] = useState(Boolean(orgId))
  const [currentOrgId, setCurrentOrgId] = useState(orgId)

  // Stats
  const [stats, setStats] = useState({
    totalProjects: null,
    activeTasks: null,
    teamMembers: null,
    productivity: null,
  })
  const [statsLoading, setStatsLoading] = useState(true)

  const [recentActivity, setRecentActivity] = useState([])
  const [showAllActivity, setShowAllActivity] = useState(false)
  const [toast, setToast] = useState(null)
  const [confirmModal, setConfirmModal] = useState(null)

  const showToast = useCallback((message, type = 'success') => {
    setToast({ message, type })
  }, [])

  const timeAgo = (date) => {
    const diff = Date.now() - new Date(date)
    const mins = Math.floor(diff / 60000)
    if (mins < 1) return 'Just now'
    if (mins < 60) return `${mins}m ago`
    const hrs = Math.floor(mins / 60)
    if (hrs < 24) return `${hrs}h ago`
    const days = Math.floor(hrs / 24)
    if (days < 7) return `${days}d ago`
    return new Date(date).toLocaleDateString('en-US',
      { month: 'short', day: 'numeric' })
  }

  // Org modal
  const [showOrgModal, setShowOrgModal] = useState(false)
  const [orgFormName, setOrgFormName] = useState('')
  const [orgError, setOrgError] = useState('')
  const [creating, setCreating] = useState(false)
  const modalRef = useRef(null)

  // Close modal on outside click
  useEffect(() => {
    const handler = (e) => {
      if (modalRef.current && !modalRef.current.contains(e.target)) {
        setShowOrgModal(false)
        setOrgFormName('')
        setOrgError('')
      }
    }
    if (showOrgModal) document.addEventListener('mousedown', handler)
    return () => document.removeEventListener('mousedown', handler)
  }, [showOrgModal])

  // Fetch stats when org exists
  useEffect(() => {
    if (!activeOrgId) {
       // fallback if activeOrgId not set
       if (orgId) setCurrentOrgId(orgId)
       else return
    } else {
       setCurrentOrgId(activeOrgId)
    }
    setHasOrg(true)
  }, [activeOrgId, orgId])

  useEffect(() => {
    if (!currentOrgId) return
    fetchStats()
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [currentOrgId])

  const fetchStats = async () => {
    try {
      // Fetch members and activity separately as well for robustness
      try {
        const [membersRes, activityRes] = await Promise.all([
          api.get(`/organizations/${currentOrgId}/members`),
          api.get(`/organizations/${currentOrgId}/activity`),
        ])
        const members = membersRes.data?.data?.members || []
        const activities = activityRes.data?.data?.activities || []
        setStats(prev => ({ ...prev, teamMembers: members.length }))
        setRecentActivity(activities)
      } catch (depErr) {
        console.error('Dependencies fetch error:', depErr)
      }

      // Fetch projects first ΓÇö isolated try-catch
      let projects = []
      try {
        const projRes = await api.get(
          `/organizations/${currentOrgId}/projects`
        )
        projects = projRes.data?.data?.projects || []
      } catch (projErr) {
        console.error('Projects fetch error:', projErr)
        // Continue with empty projects ΓÇö don't crash
      }

      // Only fetch stats if we have projects
      if (projects.length > 0) {
        try {
          const statsPromises = projects
            .slice(0, 5)
            .map(p =>
              api.get(
                `/organizations/${currentOrgId}/projects/${p._id}/stats`
              ).catch(() => ({
                data: { data: { total: 0, done: 0 } }
              }))
            )
          const statsResults = await Promise.all(
            statsPromises
          )
          const totalTasks = statsResults.reduce(
            (sum, r) =>
              sum + (r?.data?.data?.total || 0), 0
          )
          const doneTasks = statsResults.reduce(
            (sum, r) =>
              sum + (r?.data?.data?.done || 0), 0
          )
          const prod = totalTasks > 0
            ? Math.round((doneTasks / totalTasks) * 100)
            : null

          setStats(prev => ({
            ...prev,
            totalProjects: projects.length,
            activeTasks: totalTasks - doneTasks,
            productivity: prod !== null ? `${prod}%` : '0%',
          }))
        } catch (statsErr) {
          console.error('Stats fetch error:', statsErr)
        }
      } else {
        setStats(prev => ({
          ...prev,
          totalProjects: 0,
          activeTasks: 0,
          productivity: '0%',
        }))
      }
    } catch (err) {
      console.error('fetchStats outer error:', err)
    } finally {
      setStatsLoading(false)
    }
  }

  // Checklist derived from real state
  const step1Done = Boolean(user?.isVerified)
  const step2Done = Boolean(hasOrg)
  const step3Done = typeof stats.totalProjects === 'number'
                 && stats.totalProjects > 0
  const step4Done = typeof stats.teamMembers === 'number'
                 && stats.teamMembers > 1

  const checklistItems = [
    { id: 1, label: 'Verify your email',
      sub: 'Required to activate your account',
      done: step1Done, locked: false,
      isCurrentStep: !step1Done },
    { id: 2, label: 'Create your organization',
      sub: 'Set up your company workspace',
      done: step2Done, locked: false,
      isCurrentStep: step1Done && !step2Done },
    { id: 3, label: 'Create your first project',
      sub: "Start organizing your team's work",
      done: step3Done, locked: !step2Done,
      isCurrentStep: step2Done && !step3Done },
    { id: 4, label: 'Invite team members',
      sub: 'Collaborate with your team',
      done: step4Done, locked: !step2Done,
      isCurrentStep: step2Done && step3Done && !step4Done },
  ]

  const completedCount = checklistItems.filter(i => i.done).length
  const progressPercent = Math.round((completedCount / 4) * 100)

  // Create org ΓÇö REAL API CALL
  const handleCreateOrg = async () => {
    if (!orgFormName.trim()) {
      setOrgError('Organization name is required')
      return
    }
    setCreating(true)
    setOrgError('')
    try {
      // Step 1: Create org
      const res = await api.post('/organizations', {
        name: orgFormName.trim()
      })
      const org = res.data?.data?.organization || res.data
      const newOrgId = org?._id
      if (!newOrgId) throw new Error('No org ID returned')

      // Step 2: Re-fetch user to get updated organization field
      const meRes = await api.get('/auth/me')
      const updatedUser = meRes.data?.user || meRes.data
      dispatch(setCredentials({ user: updatedUser, token }))

      setHasOrg(true)
      setCurrentOrgId(newOrgId)
      setShowOrgModal(false)
      setOrgFormName('')
      showToast('Organization created successfully!')
    } catch (err) {
      console.error('Create org error:', err)
      const msg = err.response?.data?.message || 'Failed to create organization'
      setOrgError(msg)
      showToast(msg, 'error')
    } finally {
      setCreating(false)
    }
  }

  return (
    <>
      {/* ORG MODAL */}
      {showOrgModal && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-start justify-center pt-[15vh] px-4">
          <div ref={modalRef} className="bg-white dark:bg-[#141414] border border-slate-200 dark:border-[rgba(255,255,255,0.08)] rounded-2xl shadow-2xl w-full max-w-md p-6">
            <h2 className="text-lg font-bold text-slate-900 dark:text-white">Create Organization</h2>
            <p className="text-sm mt-1 text-slate-500 dark:text-slate-400">This will be your team's workspace in Orbit.</p>

            <div className="mt-5">
              <label className="text-xs font-semibold mb-1.5 block text-slate-600 dark:text-slate-400">Organization Name</label>
              <input
                autoFocus
                type="text"
                placeholder="e.g. Acme Corp, TechSoft..."
                value={orgFormName}
                onChange={(e) => { setOrgFormName(e.target.value); setOrgError(''); }}
                onKeyDown={(e) => e.key === 'Enter' && handleCreateOrg()}
                className="w-full px-3 py-2.5 rounded-lg text-sm bg-slate-50 dark:bg-[#0f0f0f] border border-slate-200 dark:border-[rgba(255,255,255,0.08)] text-slate-900 dark:text-white placeholder-slate-400 dark:placeholder-slate-600 focus:outline-none focus:ring-2 focus:ring-indigo-500/30"
              />
              {orgError && <p className="text-red-500 text-xs mt-1.5">{orgError}</p>}
            </div>

            <div className="mt-6 flex justify-end gap-3">
              <button 
                onClick={() => { setShowOrgModal(false); setOrgFormName(''); setOrgError(''); }}
                disabled={creating}
                className="px-4 py-2 text-sm font-medium text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-white/5 rounded-lg transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={handleCreateOrg}
                disabled={creating}
                className="bg-indigo-600 hover:bg-indigo-700 disabled:opacity-70 text-white px-4 py-2 rounded-lg text-sm font-semibold flex items-center gap-2 transition-colors"
              >
                {creating ? (
                  <>
                    <div className="w-4 h-4 border-2 border-white border-t-transparent animate-spin rounded-full" />
                    Creating...
                  </>
                ) : 'Create Organization'}
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="max-w-5xl mx-auto space-y-8 pb-12 pt-8 px-6">
        {/* HERO SECTION */}
        {/* HERO SECTION */}
        <section className="relative overflow-hidden py-12 px-8 md:px-14 rounded-2xl bg-white dark:bg-[#0f0f0f] border border-slate-200/80 dark:border-[rgba(255,255,255,0.07)] shadow-[0_1px_3px_rgba(0,0,0,0.05),0_20px_40px_rgba(99,102,241,0.04)] dark:shadow-none transition-colors duration-150">
          {/* LAYER 1: Animated mesh gradient background */}
          <div className="absolute -top-20 -left-20 w-[400px] h-[400px] rounded-full bg-indigo-400/12 dark:bg-indigo-500/8 blur-[80px] animate-pulse pointer-events-none z-0" style={{ animationDuration: '4s' }} />
          <div className="absolute -bottom-20 -right-10 w-[300px] h-[300px] rounded-full bg-violet-400/10 dark:bg-purple-500/6 blur-[60px] animate-pulse pointer-events-none z-0" style={{ animationDuration: '6s', animationDelay: '2s' }} />
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[500px] h-[200px] rounded-full bg-indigo-400/5 dark:bg-indigo-400/4 blur-[100px] pointer-events-none z-0" />

          {/* LAYER 2: Subtle grid pattern overlay */}
